  ('generalpolice-3218f787-moex-00018', 'generalpolice-3218f787', 'generalpolice-3218f787-moex-114-3d2b73b6', 'sub-generalpolice-3218f787-04', NULL, 'single_choice', '有關禁止法律溯及既往原則與過渡條款，下列敘述何者正確？', '["限制基本權利之法律，若適用於該法律施行前已終結之事件，乃憲法所絕對不許", "基於禁止法律溯及既往原則，對人民有利之法律，不得適用於該法律施行前已終結之事件", "基於禁止法律溯及既往原則，法律不得適用於施行前已發生，施行後繼續存在之法律關係", "立法者制定新法，若應設卻未設過渡條款適度排除新法之適用範圍，此一法律漏洞仍有由司法機關 補充之可能"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:29+00:00", "source_pdf_sha1": "7372d76e343d", "answer_pdf_sha1": "1f7241b9e683", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "302", "s": "0503", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、法學緒論、英文)", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "犯罪防治人員預防組"}'::jsonb, NULL),
  ('generalpolice-3218f787-moex-00019', 'generalpolice-3218f787', 'generalpolice-3218f787-moex-114-3d2b73b6', 'sub-generalpolice-3218f787-04', NULL, 'single_choice', '依據憲法增修條文規定，有關基本國策，國家對於公營金融機構之管理，應本下列何種原則？', '["社會平等", "企業化經營", "組織現代化", "提升競爭力"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:29+00:00", "source_pdf_sha1": "7372d76e343d", "answer_pdf_sha1": "1f7241b9e683", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "302", "s": "0503", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、法學緒論、英文)", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "犯罪防治人員預防組"}'::jsonb, NULL),
  ('generalpolice-3218f787-moex-00020', 'generalpolice-3218f787', 'generalpolice-3218f787-moex-114-3d2b73b6', 'sub-generalpolice-3218f787-04', NULL, 'single_choice', '政黨為人民之政治性結社團體，有關政黨與結社自由，下列敘述何者錯誤？', '["基於結社自由，人民得自由選擇加入或退出特定政黨", "政黨財產之使用、收益及處分，受財產權及結社自由之憲法保障", "政黨就其存續、內部之組織與運作以及對外活動等，不受國家恣意之干預", "政黨於民主政治運作有其重要性與必要性，故國家不得以任何理由解散政黨"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:29+00:00", "source_pdf_sha1": "7372d76e343d", "answer_pdf_sha1": "1f7241b9e683", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "302", "s": "0503", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、法學緒論、英文)", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "犯罪防治人員預防組"}'::jsonb, NULL),
