  ('generalpolice-3218f787-moex-00022', 'generalpolice-3218f787', 'generalpolice-3218f787-moex-114-3d2b73b6', 'sub-generalpolice-3218f787-04', NULL, 'single_choice', '下列何者與憲法第15條保障之工作權無關？', '["老年年金制度", "限制醫師藥品調劑權", "勞資爭議處理機制", "對童工的相關保護規範"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:29+00:00", "source_pdf_sha1": "7372d76e343d", "answer_pdf_sha1": "1f7241b9e683", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "302", "s": "0503", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、法學緒論、英文)", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "犯罪防治人員預防組"}'::jsonb, NULL),
  ('generalpolice-3218f787-moex-00023', 'generalpolice-3218f787', 'generalpolice-3218f787-moex-114-3d2b73b6', 'sub-generalpolice-3218f787-04', NULL, 'single_choice', '依司法院釋字第490號解釋，有關「中華民國男子依法皆有服兵役之義務」規定，下列敘述何者 錯誤？', '["基於憲法平等原則的要求，應將女子排除於兵役義務之外", "人民履行兵役義務的方式，應由立法者決定", "人民有服兵役之義務，此為憲法明文規定", "關於服兵役之重要事項，立法者應斟酌國家安全之需要，予以規定"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:29+00:00", "source_pdf_sha1": "7372d76e343d", "answer_pdf_sha1": "1f7241b9e683", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "302", "s": "0503", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、法學緒論、英文)", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "犯罪防治人員預防組"}'::jsonb, NULL),
  ('generalpolice-3218f787-moex-00024', 'generalpolice-3218f787', 'generalpolice-3218f787-moex-114-3d2b73b6', 'sub-generalpolice-3218f787-04', NULL, 'single_choice', '有關基本權，下列敘述何者正確？', '["依司法院釋字第748號解釋，若不許同性結婚，有違憲法增修條文消除性別歧視之規定", "秘密通訊自由屬於隱私權保障之具體態樣之一", "凡自然人均享有基本權，因此外國人亦可享有所有基本權", "國家基於對工作權之保障，有提供人民工作機會之義務"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:29+00:00", "source_pdf_sha1": "7372d76e343d", "answer_pdf_sha1": "1f7241b9e683", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "302", "s": "0503", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、法學緒論、英文)", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "犯罪防治人員預防組"}'::jsonb, NULL),
  ('generalpolice-3218f787-moex-00025', 'generalpolice-3218f787', 'generalpolice-3218f787-moex-114-3d2b73b6', 'sub-generalpolice-3218f787-04', NULL, 'single_choice', '甲公司僱用女性員工，惟契約條款要求女性員工若結婚則必須辭職，關於該條款效力，下列敘述何者 錯誤？', '["結婚離職條款違反憲法上的性別平等", "結婚離職條款因屬私人間之契約，對於人民之基本權未構成限制", "結婚離職條款雖違憲，但法院應透過解釋民法條文來判斷其效力，而非直接援用憲法", "法院應認定結婚離職條款違反性別平等工作法而無效"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:29+00:00", "source_pdf_sha1": "7372d76e343d", "answer_pdf_sha1": "1f7241b9e683", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "302", "s": "0503", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、法學緒論、英文)", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "犯罪防治人員預防組"}'::jsonb, NULL)
